class Solution {
    public int leastOpsExpressTarget(int x, int target) {
        if (target == 1) return 0;
        int res = 0;
        if (target % x == 0) {
            res = (int) Math.log(target / x) / Math.log(x) + (target / x == 1 ? 0 : 1);
        } else {
            res = (int) Math.log(target / x) / Math.log(x) + 2;
        }
        return res;
    }
}

